 26→const normalizeInteractionFlag = (value) => {
 27→    if(typeof value === 'boolean') return value;
 28→    if(typeof value === 'string'){
 29→        const normalized = value.trim().toLowerCase();
 30→        if(normalized === 'true') return true;
 31→        if(normalized === 'false') return false;
 32→    }
 33→    if(typeof value === 'number'){
 34→        return value === 1;
 35→    }
 36→    return Boolean(value);
 37→};
 38→
 39→const normalizeCount = (value) => {
 40→    const number = Number(value);
 41→    if(!Number.isFinite(number) || number < 0){
 42→        return 0;
 43→    }
 44→    return number;
 45→};
 46→
 47→const getNextToggleCount = (isActive, currentCount) => {
 48→    return isActive
 49→        ? Math.max(0, currentCount - 1)
 50→        : currentCount + 1;
 51→};
