 35→const parseFiniteNumber = (value, fieldName) => {
 36→    const parsed = Number(value);
 37→    if(!Number.isFinite(parsed)){
 38→        throw {status: 400, error: `${fieldName} should be a finite number`};
 39→    }
 40→    return parsed;
 41→};
