 43→const normalizeUniversePost = (post = {}) => {
 44→    const likes = Array.isArray(post?.likes) ? post.likes : [];
 45→    const likeCount = post?.like_count != null
 46→        ? Number(post.like_count)
 47→        : Number(likes?.[0]?.count ?? 0);
 48→
 49→    return {
 50→        ...post,
 51→        user_id: post?.user_id ?? post?.users?.id ?? null,
 52→        user_name: post?.user_name ?? post?.users?.name ?? null,
 53→        user_image_url: post?.user_image_url ?? post?.users?.image_url ?? null,
 54→        user_badge: post?.user_badge ?? post?.users?.badge ?? null,
 55→        display_x: post?.display_x ?? post?.settled_x ?? post?.universe_x ?? null,
 56→        display_y: post?.display_y ?? post?.settled_y ?? post?.universe_y ?? null,
 57→        like_count: Number.isFinite(likeCount) ? likeCount : 0
 58→    };
 59→};
