203→            return;
204→        }
205→        const wasBookmarked = normalizeInteractionFlag(isBookmarked);
206→        bookmarkInFlightRef.current = true;
207→        setIsBookmarked(!wasBookmarked);
208→        setBookmarkCounts((prevCount) => getNextToggleCount(wasBookmarked, normalizeCount(prevCount)));
209→        let response = null;
210→        try {
211→            response = await mutationBookmark.mutateAsync({ journalId });
212→        } finally {
213→            bookmarkInFlightRef.current = false;
214→        }
215→        
216→        if(timeOutRefBookmark.current){
217→            clearTimeout(timeOutRefBookmark.current);
218→        }
219→        if (response?.message === 'success') {
220→            setBookmarkedMessage('Post was added to your Bookmarks'); 
221→        } else if(response?.message === 'deleted'){
222→            setBookmarkedMessage('Post was removed from your Bookmarks');
223→        }
224→            
225→        timeOutRefBookmark.current = setTimeout(() => {
226→            setBookmarkedMessage('');
227→        }, 1500);
228→
229→    }
230→    const debounceClickBookmark = debounce(handleClickBookmark, 100);
