214→export const uploadJournalContentService = async(
215→    content,
216→    title,
217→    userId,
218→    postType = POST_TYPE_TEXT,
219→    canvasDocInput = null,
220→    remixSourceJournalId = null,
221→    isRemix = false
222→) =>{
223→    if(!userId){
224→        console.error('userId is undefined');
225→        throw {status: 400, error: 'userId is undefined'};
226→    }
227→
228→    const resolvedPostType = normalizePostType(postType);
229→    const trimmedTitle = typeof title === 'string' ? title.trim() : '';
230→
231→    if(!trimmedTitle){
232→        console.error('title is missing!');
233→        throw {status: 400, error: 'title is missing!'};
234→    }
235→
236→    let embeddingBody = '';
237→    const shouldSaveRemixMetadata = Boolean(
238→        remixSourceJournalId
239→        && typeof remixSourceJournalId === 'string'
240→        && remixSourceJournalId.trim()
241→    );
242→    const normalizedIsRemix = shouldSaveRemixMetadata || String(isRemix).toLowerCase() === 'true';
243→    let payload = {
244→        user_id: userId,
245→        title: trimmedTitle,
246→        post_type: resolvedPostType
247→    };
248→
249→    if(resolvedPostType === POST_TYPE_CANVAS){
250→        let parsedCanvasDoc = null;
251→        try {
252→            parsedCanvasDoc = parseCanvasDocInput(canvasDocInput);
253→        } catch (error) {
254→            console.error('invalid canvas doc on insert:', error?.message || error);
255→            throw {status: 400, error: 'invalid canvas_doc'};
256→        }
257→
258→        if(!parsedCanvasDoc){
259→            console.error('canvas_doc is missing for canvas post');
260→            throw {status: 400, error: 'canvas_doc is missing'};
261→        }
262→
263→        embeddingBody = extractCanvasPlainText(parsedCanvasDoc);
264→        payload = {
265→            ...payload,
266→            content: null,
267→            canvas_doc: parsedCanvasDoc
268→        };
269→    } else {
270→        if(!content){
271→            console.error('content is missing for text post!');
272→            throw {status: 400, error: 'content is missing for text post'};
273→        }
274→
275→        const parseData = parseTextContentSafely(content);
276→        if(!parseData){
277→            console.error('error while parsing text content data');
278→            throw {status: 400, error: 'error while parsing text content data'};
279→        }
280→
281→        embeddingBody = parseData.wholeText || '';
282→        payload = {
283→            ...payload,
284→            content: content,
285→            canvas_doc: null
286→        };
287→    }
288→
289→    const embeddingResult = await GenerateEmbeddings(trimmedTitle, embeddingBody);
290→
291→    if(!embeddingResult || !Array.isArray(embeddingResult) || embeddingResult.length === 0){
292→        console.error('error while generating embeddings on a post!');
293→        throw {status: 400, error: 'error while generating embeddings on a post!'};
294→    }
295→
296→    const insertPayload = {
297→        ...payload,
298→        embeddings: embeddingResult
299→    };
300→
301→    if(normalizedIsRemix){
302→        insertPayload.is_remix = true;
303→    }
304→    if(shouldSaveRemixMetadata){
305→        insertPayload.remix_source_journal_id = remixSourceJournalId.trim();
306→    }
307→
308→    try {
309→        const {count: postCount} = await supabase
310→            .from('journals')
311→            .select('id', {count: 'exact', head: true})
312→            .eq('user_id', userId);
313→        const home = userHomeCoords(userId);
314→        const offset = spiralLayout(postCount || 0);
315→        insertPayload.universe_x = home.x + offset.dx;
316→        insertPayload.universe_y = home.y + offset.dy;
317→    } catch (coordErr) {
318→        console.error('non-fatal: failed to compute universe coords:', coordErr?.message || coordErr);
319→    }
320→
321→    let {error} = await supabase
322→    .from('journals')
323→    .insert(insertPayload);
324→
325→    if(error){
326→        const missingRemixColumns = error?.message?.includes('is_remix') || error?.message?.includes('remix_source_journal_id');
327→        if(missingRemixColumns){
328→            const fallbackPayload = {
329→                ...payload,
330→                embeddings: embeddingResult
331→            };
332→
333→            const retry = await supabase
334→            .from('journals')
335→            .insert(fallbackPayload);
336→            error = retry.error;
337→        }
338→    }
339→
340→    if(error){
341→        console.error('supabase error while uploading content:',error.message);
342→        throw {status: 500, error: 'supabase error while uploading content'};
343→    }
344→
345→    // Non-fatal: incrementally update galaxy positions for this user
346→    try {
347→        incrementalSettleForUser(userId).catch(err =>
348→            console.error('non-fatal: incremental settle failed:', err?.message || err)
349→        );
350→    } catch (settleErr) {
351→        console.error('non-fatal: incremental settle failed:', settleErr?.message || settleErr);
352→    }
353→
354→    return true;
355→}
