 264→const hasSupportedMediaExtension = (fileName = '') => {
 265→    const lowerFileName = fileName.toLowerCase();
 266→    return PROFILE_MEDIA_EXTENSIONS.some((ext) => lowerFileName.endsWith(ext));
 267→};
 268→
 269→const parseMediaTimestamp = (item = {}) => {
 270→    const fileName = item?.name || '';
 271→    const timestampPrefix = fileName.match(/^(\d+)_/);
 272→
 273→    if(timestampPrefix?.[1]){
 274→        const parsedPrefix = Number(timestampPrefix[1]);
 275→        if(!Number.isNaN(parsedPrefix)){
 276→            return parsedPrefix;
 277→        }
 278→    }
 279→
 280→    const parsedDate = Date.parse(item?.created_at || item?.updated_at || '');
 281→    return Number.isNaN(parsedDate) ? 0 : parsedDate;
 282→};
 283→
 284→const createInitialMediaCursorState = () => ({
 285→    offsets: Object.fromEntries(PROFILE_MEDIA_BUCKETS.map((bucket) => [bucket, 0])),
 286→    exhausted: Object.fromEntries(PROFILE_MEDIA_BUCKETS.map((bucket) => [bucket, false])),
 287→    pending: []
 288→});
 289→
 290→const parseMediaCursor = (cursor) => {
 291→    if(!cursor){
 292→        return createInitialMediaCursorState();
 293→    }
 294→
 295→    try {
 296→        const decoded = Buffer.from(cursor, 'base64').toString('utf8');
 297→        const parsed = JSON.parse(decoded);
 298→        const initial = createInitialMediaCursorState();
 299→
 300→        if(parsed?.offsets && typeof parsed.offsets === 'object'){
 301→            PROFILE_MEDIA_BUCKETS.forEach((bucket) => {
 302→                const value = Number(parsed.offsets[bucket]);
 303→                initial.offsets[bucket] = Number.isNaN(value) || value < 0 ? 0 : value;
 304→            });
 305→        }
 306→
 307→        if(parsed?.exhausted && typeof parsed.exhausted === 'object'){
 308→            PROFILE_MEDIA_BUCKETS.forEach((bucket) => {
 309→                initial.exhausted[bucket] = Boolean(parsed.exhausted[bucket]);
 310→            });
 311→        }
 312→
 313→        if(Array.isArray(parsed?.pending)){
 314→            initial.pending = parsed.pending
 315→                .filter((item) => PROFILE_MEDIA_BUCKETS.includes(item?.bucket) && typeof item?.path === 'string' && typeof item?.name === 'string')
 316→                .map((item) => ({
 317→                    bucket: item.bucket,
 318→                    path: item.path,
 319→                    name: item.name,
 320→                    createdAt: item.createdAt || null,
 321→                    timestamp: Number(item.timestamp) || 0
 322→                }));
 323→        }
 324→
 325→        return initial;
 326→    } catch {
 327→        return createInitialMediaCursorState();
 328→    }
 329→};
 330→
 331→const encodeMediaCursor = (state) => {
 332→    const payload = JSON.stringify(state);
 333→    return Buffer.from(payload, 'utf8').toString('base64');
 334→};
 335→
 336→const parseCanvasGalleryCursor = (cursor, expectedSort = 'hottest') => {
 337→    const fallback = {
 338→        offset: 0,
 339→        sort: expectedSort
 340→    };
 341→
 342→    if(!cursor){
 343→        return fallback;
 344→    }
 345→
 346→    try {
 347→        const decoded = Buffer.from(cursor, 'base64').toString('utf8');
 348→        const parsed = JSON.parse(decoded);
 349→        const parsedSort = typeof parsed?.sort === 'string' && parsed.sort.toLowerCase().trim() === 'newest'
 350→            ? 'newest'
 351→            : 'hottest';
 352→
 353→        if(parsedSort !== expectedSort){
 354→            return fallback;
 355→        }
 356→
 357→        const parsedOffset = Number(parsed?.offset);
 358→        const normalizedOffset = Number.isNaN(parsedOffset) || parsedOffset < 0
 359→            ? 0
 360→            : Math.floor(parsedOffset);
 361→
 362→        return {
 363→            offset: normalizedOffset,
 364→            sort: parsedSort
 365→        };
 366→    } catch {
 367→        return fallback;
 368→    }
 369→};
