 692→export const getMonthlyHottestJournalsService = async(limit, userId) => {
 693→    if(isNaN(limit) || limit < 1 || limit > 10){
 694→        throw {status: 400, error: 'limit should be an integer between 1 and 10'};
 695→    }
 696→
 697→    const parsedLimit = parseInt(limit);
 698→    const now = new Date();
 699→    const monthStartUtc = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1, 0, 0, 0, 0));
 700→    const nextMonthStartUtc = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth() + 1, 1, 0, 0, 0, 0));
 701→
 702→    const {data: journals, error: journalsError} = await supabase
 703→        .from('journals')
 704→        .select(`
 705→            *,
 706→            users(*),
 707→            like_count: likes(count),
 708→            comment_count: comments(count),
 709→            bookmark_count: bookmarks(count)
 710→        `)
 711→        .eq('privacy', 'public')
 712→        .gte('created_at', monthStartUtc.toISOString())
 713→        .lt('created_at', nextMonthStartUtc.toISOString());
 714→
 715→    if(journalsError){
 716→        console.error('supabase error while fetching monthly hottest journals:', journalsError.message);
 717→        throw {status: 500, error: 'supabase error while fetching monthly hottest journals'};
 718→    }
 719→
 720→    const journalsWithInteractions = await attachUserInteractionFlags(journals || [], userId);
 721→    const scored = journalsWithInteractions.map((journal) => {
 722→        const likes = journal?.like_count?.[0]?.count || 0;
 723→        const comments = journal?.comment_count?.[0]?.count || 0;
 724→        const bookmarks = journal?.bookmark_count?.[0]?.count || 0;
 725→        const views = journal?.views || 0;
 726→        const hotScore = (views * 6) + (likes * 3) + (comments * 2) + (bookmarks * 2);
 727→
 728→        return {
 729→            ...journal,
 730→            hot_score: hotScore
 731→        };
 732→    });
 733→
 734→    scored.sort((a, b) => {
 735→        const scoreDiff = (b?.hot_score || 0) - (a?.hot_score || 0);
 736→        if(scoreDiff !== 0){
 737→            return scoreDiff;
 738→        }
 739→
 740→        const dateDiff = new Date(b?.created_at || 0) - new Date(a?.created_at || 0);
 741→        if(dateDiff !== 0){
 742→            return dateDiff;
 743→        }
 744→
 745→        return (b?.id || 0) - (a?.id || 0);
 746→    });
 747→
 748→    return {
 749→        data: scored.slice(0, parsedLimit),
 750→        period: {
 751→            startUtc: monthStartUtc.toISOString(),
 752→            endUtc: nextMonthStartUtc.toISOString(),
 753→            timezone: 'UTC'
 754→        },
 755→        totalCandidates: scored.length
 756→    };
 757→}
