 767→export const getCanvasGalleryService = async(limit = CANVAS_GALLERY_LIMIT_DEFAULT, userId, sort = 'hottest', cursor = null) => {
 768→    if(isNaN(limit) || limit < 1 || limit > CANVAS_GALLERY_LIMIT_MAX){
 769→        throw {status: 400, error: `limit should be an integer between 1 and ${CANVAS_GALLERY_LIMIT_MAX}`};
 770→    }
 771→
 772→    const parsedLimit = parseInt(limit);
 773→    const normalizedSort = typeof sort === 'string' ? sort.toLowerCase().trim() : 'hottest';
 774→    const isNewest = normalizedSort === 'newest';
 775→    const parsedCursor = parseCanvasGalleryCursor(cursor, isNewest ? 'newest' : 'hottest');
 776→    const cursorOffset = parsedCursor.offset;
 777→
 778→    const baseQuery = supabase
 779→        .from('journals')
 780→        .select(`
 781→            *,
 782→            users(*),
 783→            like_count: likes(count),
 784→            comment_count: comments(count),
 785→            bookmark_count: bookmarks(count)
 786→        `)
 787→        .eq('privacy', 'public')
 788→        .eq('post_type', 'canvas')
 789→        .order('created_at', {ascending: false})
 790→        .order('id', {ascending: false});
 791→
 792→    const {data: journals, error: journalsError} = isNewest
 793→        ? await baseQuery.range(cursorOffset, cursorOffset + parsedLimit)
 794→        : await baseQuery.limit(CANVAS_GALLERY_HOT_FETCH_LIMIT);
 795→
 796→    if(journalsError){
 797→        console.error('supabase error while fetching canvas gallery journals:', journalsError.message);
 798→        throw {status: 500, error: 'supabase error while fetching canvas gallery journals'};
 799→    }
 800→
 801→    const enrichedJournals = await attachUserInteractionFlags(journals || [], userId);
 802→    const normalizedJournals = enrichedJournals.map((journal) => ({
 803→        ...journal,
 804→        hot_score: scoreJournalHotness(journal)
 805→    }));
 806→
 807→    if(!isNewest){
 808→        normalizedJournals.sort((a, b) => {
 809→            const scoreDiff = (b.hot_score || 0) - (a.hot_score || 0);
 810→            if(scoreDiff !== 0){
 811→                return scoreDiff;
 812→            }
 813→
 814→            const dateDiff = new Date(b?.created_at || 0) - new Date(a?.created_at || 0);
 815→            if(dateDiff !== 0){
 816→                return dateDiff;
 817→            }
 818→
 819→            return (b?.id || 0) - (a?.id || 0);
 820→        });
 821→    }
 822→
 823→    const paginatedJournals = isNewest
 824→        ? normalizedJournals
 825→        : normalizedJournals.slice(cursorOffset, cursorOffset + parsedLimit + 1);
 826→    const hasMore = paginatedJournals.length > parsedLimit;
 827→    const data = hasMore ? paginatedJournals.slice(0, parsedLimit) : paginatedJournals;
 828→    const nextCursor = hasMore
 829→        ? encodeCanvasGalleryCursor(cursorOffset + data.length, isNewest ? 'newest' : 'hottest')
 830→        : null;
 831→
 832→    return {
 833→        data: data,
 834→        sort: isNewest ? 'newest' : 'hottest',
 835→        totalCandidates: normalizedJournals.length,
 836→        hasMore: hasMore,
