1283→export const searchJournalsService = async(query, limit, userId) => {
1284→    const normalizedQuery = normalizeSearchQuery(query);
1285→    if(!normalizedQuery || normalizedQuery.length < SEARCH_QUERY_MIN_LENGTH){
1286→        throw {status: 400, error: `query should be at least ${SEARCH_QUERY_MIN_LENGTH} characters`};
1287→    }
1288→
1289→    if(isNaN(limit) || limit < 1 || limit > SEARCH_LIMIT_MAX){
1290→        throw {status: 400, error: `limit should be an integer between 1 and ${SEARCH_LIMIT_MAX}`};
1291→    }
1292→
1293→    const parsedLimit = parseInt(limit);
1294→    const fetchLimit = Math.min(parsedLimit * 3, 60);
1295→
1296→    const selectColumns = `
1297→        *,
1298→        users(*),
1299→        like_count: likes(count),
1300→        comment_count: comments(count),
1301→        bookmark_count: bookmarks(count)
1302→    `;
1303→
1304→    // Prefer semantic retrieval. If pgvector RPC is unavailable or errors,
1305→    // fallback to keyword search so endpoint still returns useful data.
1306→    try {
1307→        const queryEmbedding = await GenerateEmbeddings(normalizedQuery, '');
1308→
1309→        if(Array.isArray(queryEmbedding) && queryEmbedding.length > 0){
1310→            const {data: matches, error: matchError} = await supabase.rpc('match_public_journals', {
1311→                query_embedding: queryEmbedding,
1312→                match_count: fetchLimit,
1313→                similarity_threshold: 0.35
1314→            });
1315→
1316→            if(matchError){
1317→                console.error('semantic search rpc error:', matchError.message);
1318→            } else if(Array.isArray(matches) && matches.length > 0){
1319→                const matchIds = matches.map((row) => row.id);
1320→                const similarityMap = new Map(matches.map((row) => [row.id, row.similarity]));
1321→
1322→                const {data: journals, error: errorJournals} = await supabase
1323→                    .from('journals')
1324→                    .select(selectColumns)
1325→                    .in('id', matchIds)
1326→                    .eq('privacy', 'public');
1327→
1328→                if(errorJournals){
1329→                    console.error('supabase error while fetching semantic search journals:', errorJournals.message);
1330→                    throw {status: 500, error: 'supabase error while fetching semantic search journals'};
1331→                }
1332→
1333→                const journalById = new Map((journals || []).map((journal) => [journal.id, journal]));
1334→                const orderedSemantic = matchIds
1335→                    .map((id) => journalById.get(id))
1336→                    .filter(Boolean)
1337→                    .map((journal) => ({
1338→                        ...journal,
1339→                        similarity: similarityMap.get(journal.id) || null
1340→                    }));
1341→
1342→                const withInteraction = await attachUserInteractionFlags(orderedSemantic, userId);
1343→                const hasMore = withInteraction.length > parsedLimit;
1344→
1345→                return {
1346→                    data: hasMore ? withInteraction.slice(0, parsedLimit) : withInteraction,
1347→                    hasMore: hasMore,
1348→                    mode: 'semantic'
1349→                };
1350→            }
1351→        }
1352→    } catch (error) {
1353→        console.error('semantic embedding/search fallback error:', error?.message || error);
1354→    }
1355→
1356→    const escapedQuery = normalizedQuery.replace(/[%_]/g, (match) => `\\${match}`);
1357→
1358→    const [titleResult, contentResult] = await Promise.all([
1359→        supabase
1360→            .from('journals')
1361→            .select(selectColumns)
1362→            .eq('privacy', 'public')
1363→            .ilike('title', `%${escapedQuery}%`)
1364→            .order('created_at', {ascending: false})
1365→            .order('id', {ascending: false})
1366→            .limit(parsedLimit + 1),
1367→        supabase
1368→            .from('journals')
1369→            .select(selectColumns)
1370→            .eq('privacy', 'public')
1371→            .ilike('content', `%${escapedQuery}%`)
1372→            .order('created_at', {ascending: false})
1373→            .order('id', {ascending: false})
1374→            .limit(parsedLimit + 1)
1375→    ]);
1376→
1377→    if(titleResult.error || contentResult.error){
1378→        console.error('keyword search error:', titleResult.error?.message || contentResult.error?.message);
1379→        throw {status: 500, error: 'supabase error while searching journals'};
1380→    }
1381→
1382→    const keywordMap = new Map();
1383→    (titleResult.data || []).forEach((journal) => {
1384→        keywordMap.set(journal.id, journal);
1385→    });
1386→    (contentResult.data || []).forEach((journal) => {
1387→        if(!keywordMap.has(journal.id)){
1388→            keywordMap.set(journal.id, journal);
1389→        }
1390→    });
1391→
1392→    const keywordJournals = [...keywordMap.values()];
1393→
1394→    const withInteraction = await attachUserInteractionFlags(keywordJournals || [], userId);
1395→    const hasMore = withInteraction.length > parsedLimit;
1396→
1397→    return {
1398→        data: hasMore ? withInteraction.slice(0, parsedLimit) : withInteraction,
1399→        hasMore: hasMore,
1400→        mode: 'keyword'
1401→    };
1402→}
