439→                        </button>
440→                    </div>
441→
442→                    {postData?.postType === 'canvas' && (
443→                        <div className="cv-canvas-actions">
444→                            <button
445→                                type="button"
446→                                className="cv-remix-btn"
447→                                onClick={handleRemixCanvas}
448→                                disabled={!session}
449→                                title={session ? "Remix this canvas" : "Sign in to remix"}
450→                            >
451→                                Remix this Canvas
452→                            </button>
453→                        </div>
454→                    )}
455→
456→                    {/* Body content */}
457→                    <div className="cv-body">
458→                        {postData?.postType === 'canvas' ? (
459→                            <CanvasViewer
460→                                canvasDoc={postData?.canvasDoc}
461→                            />
462→                        ) : (
463→                            <LexicalComposer initialConfig={{
464→                                namespace: "ContentViewer",
465→                                theme: theme,
466→                                editable: false,
467→                                editorState: postData?.content,
468→                                nodes: [HeadingNode, ImageNode, QuoteNode],
469→                                onError(error) {
470→                                    throw error;
471→                                },
472→                            }}>
473→                                <RichTextPlugin
474→                                    contentEditable={<ContentEditable />}
475→                                    ErrorBoundary={LexicalErrorBoundary}
476→                                />
477→                            </LexicalComposer>
478→                        )}
479→                    </div>
480→                </article>
481→
482→                {/* Toast notification */}
483→            <AnimatePresence>
484→                {bookmarkedMessage && (
485→                    <motion.div
486→                        className="cv-toast"
487→                        initial={{ opacity: 0, y: 8 }}
488→                        animate={{ opacity: 1, y: 0 }}
489→                        exit={{ opacity: 0, y: 8 }}
490→                        transition={{ duration: 0.2, ease: "easeOut" }}
491→                    >
492→                        {bookmarkedMessage}
493→                    </motion.div>
494→                )}
495→            </AnimatePresence>
496→            </div>
497→        </>
498→    )
499→}
