629→    if(error){
630→        console.error('supabase error while fetching journals:', error.message);
631→        throw{status: 500, error: 'supabase error while fetching journals'}
632→    }
633→
634→    if(data.length === 0){
635→        const journalData = {
636→            data: [],
637→            hasMore: false
638→        }
639→        return journalData
640→    }
641→
642→    // If userId is provided, fetch personalization (likes/bookmarks)
643→    // Otherwise return journals with has_liked/has_bookmarked defaulting to false
644→    let userHasLikedSet = new Set();
645→    let userHasBookmarkedSet = new Set();
