844→        throw { status: 400, error: 'journalId is undefined' };
845→    }
846→
847→    const { data: journal, error: journalError } = await supabase
848→        .from('journals')
849→        .select(`
850→            *,
851→            users(*),
852→            like_count: likes(count),
853→            comment_count: comments(count),
854→            bookmark_count: bookmarks(count)
855→        `)
856→        .eq('id', journalId)
857→        .eq('privacy', 'public')
