863→    }
864→
865→    if (!journal) {
866→        return null;
867→    }
868→
869→    let hasLiked = false;
870→    let hasBookmarked = false;
871→
872→    if (userId) {
873→        const [likeResult, bookmarkResult] = await Promise.all([
874→            supabase
875→                .from('likes')
876→                .select('journal_id', { count: 'exact', head: true })
877→                .eq('journal_id', journalId)
878→                .eq('user_id', userId),
879→            supabase
880→                .from('bookmarks')
881→                .select('journal_id', { count: 'exact', head: true })
882→                .eq('journal_id', journalId)
883→                .eq('user_id', userId)
884→        ]);
885→
886→        if (likeResult.error || bookmarkResult.error) {
887→            console.error(
888→                'supabase error while fetching journal interactions:',
889→                likeResult.error?.message || bookmarkResult.error?.message
890→            );
891→            throw { status: 500, error: 'supabase error while fetching journal interactions' };
892→        }
893→
894→        hasLiked = (likeResult.count || 0) > 0;
895→        hasBookmarked = (bookmarkResult.count || 0) > 0;
896→    }
897→
898→    return {
899→        ...journal,
900→        has_liked: hasLiked,
901→        has_bookmarked: hasBookmarked
902→    };
903→}
