    };

    if (!isOpen) return null;

    return (
        <AnimatePresence>
            <motion.div className="repost-modal-overlay" onClick={onClose}
                initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
